svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
    var dataLayerEl = document.getElementById('data-layer');
    var edgeLayer = document.getElementById('edge-layer');
    var nodeLayer = document.getElementById('node-layer');
    var plotShiftX = 0;
    var legendRoot = document.getElementById('legend-root');

    var nodes = [
      { id:'ceo',   label:'Chief Product', sub:'Officer',       parent:null,  branch:1 },
      { id:'eng',   label:'Engineering',   sub:'42 engineers',  parent:'ceo', branch:2 },
      { id:'des',   label:'Design',        sub:'11 designers',  parent:'ceo', branch:3 },
      { id:'dat',   label:'Data & ML',     sub:'18 analysts',   parent:'ceo', branch:4 },
      { id:'fe',    label:'Frontend',      sub:'14 engineers',  parent:'eng', branch:2 },
      { id:'be',    label:'Backend',       sub:'18 engineers',  parent:'eng', branch:2 },
      { id:'infra', label:'Platform',      sub:'10 engineers',  parent:'eng', branch:2 },
      { id:'ux',    label:'UX Research',   sub:'5 researchers', parent:'des', branch:3 },
      { id:'vis',   label:'Visual Design', sub:'6 designers',   parent:'des', branch:3 },
      { id:'anal',  label:'Analytics',     sub:'8 analysts',    parent:'dat', branch:4 },
      { id:'ml',    label:'ML Eng',        sub:'10 engineers',  parent:'dat', branch:4 },
      { id:'mob',   label:'Mobile',        sub:'7 engineers',   parent:'fe',  branch:2 },
      { id:'web',   label:'Web',           sub:'7 engineers',   parent:'fe',  branch:2 },
      { id:'api',   label:'API',           sub:'9 engineers',   parent:'be',  branch:2 }
    ];

    var byId = {};
    var root = null;
    var plotL = 68;
    var plotR = 850;
    var plotT = 100;
    var plotB = 500;
    var nodeW = 100;
    var nodeH = 40;
    var nodeItems = [];
    var edgeItems = [];

    function mixColors(colorA, colorB, ratio) {
      var rgbA = ctx.colorToRgb(colorA);
      var rgbB = ctx.colorToRgb(colorB);
      var weight = Math.max(0, Math.min(1, Number(ratio) || 0));

      function channel(index) {
        return Math.round(rgbA[index] * (1 - weight) + rgbB[index] * weight);
      }

      return 'rgb(' + channel(0) + ', ' + channel(1) + ', ' + channel(2) + ')';
    }

    function getNodeColors(node) {
      var wantDark = svgEl.classList.contains('dark');
      var surface = wantDark ? '#1C1B1F' : '#FFFBFE';
      var rootFill = wantDark ? '#2B2930' : '#EEE7F2';
      var rootStroke = wantDark ? '#938F99' : '#79747E';
      var depthBlend = [0.22, 0.42, 0.58, 0.70];
      var strokeBlend = [0.10, 0.18, 0.28, 0.36];
      var blendIndex = Math.min(Math.max(0, node.depth - 1), depthBlend.length - 1);
      var baseColor;
      var fillColor;
      var strokeColor;

      if (node.depth === 0) {
        return {
          fill: rootFill,
          stroke: rootStroke
        };
      }

      baseColor = ctx.getSeriesToneColor(node.branch, 0);
      fillColor = mixColors(baseColor, surface, depthBlend[blendIndex]);
      strokeColor = mixColors(baseColor, surface, strokeBlend[blendIndex]);

      return {
        fill: fillColor,
        stroke: strokeColor
      };
    }

    function applyNodeColors() {
      nodes.forEach(function (node) {
        if (!node._rect || !node._title || !node._sub) return;
        var colors = getNodeColors(node);
        var textColors = ctx.getReadableTextColors(colors.fill);

        node._rect.style.fill = colors.fill;
        node._rect.style.stroke = colors.stroke;
        node._title.setAttribute('fill', textColors.title);
        node._sub.setAttribute('fill', textColors.sub);
      });
    }

    nodes.forEach(function (node) {
      byId[node.id] = node;
      node.children = [];
    });

    nodes.forEach(function (node) {
      if (node.parent) {
        byId[node.parent].children.push(node);
      } else {
        root = node;
      }
    });

    function setDepth(node, depth) {
      node.depth = depth;
      node.children.forEach(function (child) {
        setDepth(child, depth + 1);
      });
    }
    setDepth(root, 0);

    var maxDepth = 0;
    nodes.forEach(function (node) {
      if (node.depth > maxDepth) maxDepth = node.depth;
    });

    var colW = (plotR - plotL) / (maxDepth + 1);
    var leafSlot = 0;
    var totalLeaves = nodes.filter(function (node) { return node.children.length === 0; }).length;
    var slotH = (plotB - plotT) / (totalLeaves + 1);

    function assignY(node) {
      if (node.children.length === 0) {
        leafSlot += 1;
        node.cy = plotT + leafSlot * slotH;
      } else {
        node.children.forEach(assignY);
        var ys = node.children.map(function (child) { return child.cy; });
        node.cy = (Math.min.apply(null, ys) + Math.max.apply(null, ys)) / 2;
      }
    }
    assignY(root);

    nodes.forEach(function (node) {
      node.cx = plotL + (node.depth + 0.5) * colW;
    });

    nodes.forEach(function (node) {
      if (!node.parent) return;
      var parent = byId[node.parent];
      var x1 = parent.cx + nodeW / 2;
      var x2 = node.cx - nodeW / 2;
      var mx = (x1 + x2) / 2;
      var y1 = parent.cy;
      var y2 = node.cy;
      var edge = ctx.el('path', {
        'class': 'edge',
        d: 'M' + x1 + ',' + y1 + ' H' + mx + ' V' + y2 + ' H' + x2
      });
      edgeLayer.appendChild(edge);
      node._edge = edge;
      edgeItems.push(edge);
    });

    nodes.forEach(function (node) {
      var colors = getNodeColors(node);
      var textColors = ctx.getReadableTextColors(colors.fill);
      var group = ctx.el('g', {
        id: 'ng-' + node.id,
        'class': 'node-g',
        'data-node-id': node.id,
        'data-item-cx': String(node.cx),
        'data-item-top': String(node.cy - nodeH / 2)
      });
      var rect = ctx.el('rect', {
        x: node.cx - nodeW / 2,
        y: node.cy - nodeH / 2,
        width: nodeW,
        height: nodeH,
        rx: 8,
        'class': 'node-rect'
      });
      var title = ctx.el('text', {
        x: node.cx,
        y: node.cy - 5,
        'text-anchor': 'middle',
        'class': 'node-title',
        fill: textColors.title
      });
      var sub = ctx.el('text', {
        x: node.cx,
        y: node.cy + 11,
        'text-anchor': 'middle',
        'class': 'node-sub',
        fill: textColors.sub
      });

      rect.style.fill = colors.fill;
      rect.style.stroke = colors.stroke;
      title.textContent = node.label;
      sub.textContent = node.sub;

      group.appendChild(rect);
      group.appendChild(title);
      group.appendChild(sub);
      nodeLayer.appendChild(group);
      node._group = group;
      node._rect = rect;
      node._title = title;
      node._sub = sub;
      nodeItems.push(group);
    });

    svgEl._onModeChange = function () {
      applyNodeColors();
    };

    ctx.initStandardLegend({
      legendEl: legendRoot,
      title: 'SERIES',
      items: [
        { cls: 'series-1', label: 'Leadership', value: '1 role' },
        { cls: 'series-2', label: 'Engineering', value: '7 teams' },
        { cls: 'series-3', label: 'Design', value: '3 teams' },
        { cls: 'series-4', label: 'Data & ML', value: '3 teams' }
      ]
    });

    plotShiftX = ctx.rebalancePlotArea({
      legendEl: legendRoot,
      measureNodes: [dataLayerEl],
      moveNodes: [dataLayerEl],
      slotLeft: 0,
      legendGap: 24,
      clamp: true
    }).shiftX || 0;

    ctx.initRevealSequence(edgeItems, {
      animationName: 'fadeIn',
      duration: 0.8,
      easing: 'ease-out',
      delays: edgeItems.map(function (_, index) {
        return ctx.getStaggerDelay(index, edgeItems.length + nodeItems.length, 1.0);
      })
    });

    ctx.initRevealSequence(nodeItems, {
      animationName: 'fadeIn',
      duration: 0.8,
      easing: 'ease-out',
      delays: nodeItems.map(function (_, index) {
        return ctx.getStaggerDelay(edgeItems.length + index, edgeItems.length + nodeItems.length, 1.0);
      })
    });

    var connectedHover = ctx.initConnectedHover(dataLayerEl, nodeItems, {
      allNodes: nodeItems,
      allEdges: edgeItems,
      getRelatedItems: function (itemEl) {
        var node = byId[itemEl.getAttribute('data-node-id')];
        var related = [];
        if (!node) return related;
        if (node.parent && byId[node.parent] && byId[node.parent]._group) {
          related.push(byId[node.parent]._group);
        }
        node.children.forEach(function (child) {
          if (child._group) related.push(child._group);
        });
        return related;
      },
      getRelatedEdges: function (itemEl) {
        var node = byId[itemEl.getAttribute('data-node-id')];
        var related = [];
        if (!node) return related;
        if (node._edge) related.push(node._edge);
        node.children.forEach(function (child) {
          if (child._edge) related.push(child._edge);
        });
        return related;
      }
    });

    ctx.initStandardTooltip(dataLayerEl, nodeItems, {
      tip: document.getElementById('tip'),
      plotL: plotL,
      plotR: plotR,
      plotT: plotT,
      plotB: plotB,
      placement: 'side',
      minWidth: 220,
      paddingX: 20,
      paddingY: 18,
      lineHeights: [42, 32, 32],
      trackPointer: false,
      getAnchor: function (itemEl) {
        return {
          x: (Number(itemEl.getAttribute('data-item-cx')) || 0) + plotShiftX,
          y: Number(itemEl.getAttribute('data-item-top')) || 0
        };
      },
      getContent: function (itemEl) {
        var node = byId[itemEl.getAttribute('data-node-id')];
        var depthLabel = ['Root', 'Dept', 'Team', 'Sub-team'][node ? node.depth : 0] || ('Depth ' + (node ? node.depth : 0));
        return {
          primary: node ? node.label : '',
          label: depthLabel,
          meta: node ? node.sub : ''
        };
      },
      onActivate: function (itemEl) {
        connectedHover.activate(itemEl);
      },
      onDeactivate: function () {
        connectedHover.clear();
      },
      leaveTarget: dataLayerEl
    });

    ctx.markReadyAfterReveal(dataLayerEl, {
      delays: nodeItems.map(function (_, index) {
        return ctx.getStaggerDelay(edgeItems.length + index, edgeItems.length + nodeItems.length, 1.0);
      }).concat(edgeItems.map(function (_, index) {
        return ctx.getStaggerDelay(index, edgeItems.length + nodeItems.length, 1.0);
      })),
      duration: 0.8,
      buffer: 0.1
    });

  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
